const windowDays = parseInt($env.RENEWAL_WINDOW_DAYS || 60, 10);
const healthThreshold = parseInt($env.RENEWAL_HEALTH_THRESHOLD || 70, 10);
const today = new Date();
const cutoff = new Date(); cutoff.setDate(today.getDate() + windowDays);
const accounts = $input.all().map(i=>i.json);
const expiring = accounts.filter(a => {
  if (!a.contract_end_date) return false;
  const end = new Date(a.contract_end_date);
  return end >= today && end <= cutoff;
}).map(a => {
  const end = new Date(a.contract_end_date);
  const days_to_renewal = Math.ceil((end-today)/86400000);
  const health = parseInt(a.health_score || 100, 10);
  const is_at_risk = health < healthThreshold;
  const priority = (days_to_renewal <= 30 && is_at_risk) ? 'critical' : is_at_risk ? 'high' : days_to_renewal <= 30 ? 'medium' : 'low';
  return { ...a, days_to_renewal, health_score: health, is_at_risk, priority };
}).sort((a,b) => { const order = {critical:0,high:1,medium:2,low:3}; return order[a.priority]-order[b.priority] || a.days_to_renewal-b.days_to_renewal; });
const critical = expiring.filter(a=>a.priority==='critical');
const high = expiring.filter(a=>a.priority==='high');
const total_mrr_at_risk = expiring.filter(a=>a.is_at_risk).reduce((s,a)=>s+parseFloat(a.mrr||0),0);
return [{ json: { week: today.toISOString().slice(0,10), window_days: windowDays, health_threshold: healthThreshold, total_expiring: expiring.length, critical_count: critical.length, high_count: high.length, total_mrr_at_risk: Math.round(total_mrr_at_risk), expiring, critical, high } }];

